class Solution:
    def minimumChanges(self, s: str, k: int) -> int:
        def min_changes(substring):
            n = len(substring)
            res = n
            for d in range(1, n):
                if n % d == 0:
                    count = 0
                    for i in range(d):
                        group = substring[i::d]
                        count += sum(group.count(c) != group.count(group[0]) for c in set(group)) // 2
                    res = min(res, count)
            return res

        n = len(s)
        dp = [[float('inf')] * (k + 1) for _ in range(n + 1)]
        dp[0][0] = 0
        for i in range(1, n + 1):
            for j in range(1, min(i // 2 + 1, k + 1)):
                for m in range(j - 1, i):
                    dp[i][j] = min(dp[i][j], dp[m][j - 1] + min_changes(s[m:i]))
        return dp[n][k]

